tal.","warning":true},{"label":"Key authority","value":"OIF · Family reunification"},{"label":"After approval","value":"Enter on national D visa if required; collect residence card; register address locally."}],"eligibility":[{"criterion":"Valid marriage certificate (apostilled/translated)","met":true},{"criterion":"Sponsor legal status in destination country","met":true},{"criterion":"Proof of genuine relationship","met":true},{"criterion":"Sponsor adequate income and housing","met":false,"note":"Verify current thresholds"},{"criterion":"Health insurance coverage","met":false},{"criterion":"Language/integration requirements (if applicable)","met":false,"note":"Country-specific exemptions may apply"}],"redFlagsBanner":"If refused, address embassy concerns on relationship or sponsor eligibility before reapplication.","redFlags":[{"title":"Sponsor income/housing insufficient","description":"Sponsor cannot prove adequate apartment size or income.","fix":"Collect sponsor employment contract, salary slips, lease with square metres","severity":"Very common"},{"title":"Missing A1 Hungarian certificate","description":"Spouse applied without required basic Hungarian.","fix":"Complete Goethe A1 or verify exemption applies","severity":"Common"},{"title":"Weak relationship evidence","description":"Few photos, no visit history, recent marriage unexplained.","fix":"Chronological relationship timeline; visit stamps; communication logs","severity":"Common"},{"title":"Marriage not registered/apostilled","description":"Indian marriage certificate not properly legalised.","fix":"Apostille and certified Hungarian translation","severity":"Common"},{"title":"Sponsor permit expiring","description":"Sponsor residence permit near expiry or uncertain status.","fix":"Verify sponsor valid long-term status before apply","severity":"High"},{"title":"Prior refusals hidden","description":"Schengen or national visa refusals not disclosed.","fix":"Full disclosure in cover letter","severity":"High"}]